// Safely extract primitives from the error trigger payload
// Avoid deep-walking raw n8n objects which trigger sandbox env var guards
const raw = $input.first()?.json || {};

// Safely read nested values using optional chaining on plain copies
const safeStr = (val) => (typeof val === 'string' ? val : null);
const safeObj = (val) => {
  if (!val || typeof val !== 'object') return {};
  try { return JSON.parse(JSON.stringify(val)); } catch { return {}; }
};

const event = safeObj(raw);
const workflowMeta = event.workflow || {};
const executionMeta = event.execution || {};
const errorMeta = executionMeta.error || {};

const now = new Date();
const processedAt = now.toISOString();
const workflowId = safeStr(workflowMeta.id) || safeStr(executionMeta.workflowId) || 'unknown_workflow';
const workflowName = safeStr(workflowMeta.name) || 'Unknown Workflow';
const lastNode = safeStr(executionMeta.lastNodeExecuted) || null;
const errorMessage = safeStr(errorMeta.message) || safeStr(errorMeta.description) || 'Unknown execution error';

const payload = {
  received_date: null,
  provider: null,
  provider_contact: { name: null, company: null, phone: null, email: null },
  owner: null,
  address: { country: 'Austria', postal_code: null, city: null, street: null, house_number: null },
  areas: { usable_area_m2: null, plot_area_m2: null },
  financials: {
    target_rent_pa_eur: null, actual_rent_pa_eur: null, asking_price_eur: null,
    price_per_m2_usable_area: null, price_per_m2_land: null,
  },
  property: {
    property_type: null, ownership_type: null, construction_year: null,
    heritage_protection: null, vacancy: null, parking_spaces: null,
  },
  returns: { gross_initial_yield_actual: null, gross_initial_yield_target: null },
  notes: 'Workflow failure captured by BIG error handler.',
  location_enrichment: {
    latitude: null, longitude: null, aerial_image_url: null, location_description: null,
    public_transport_access: null, distance_city_center_min: null,
    distance_train_station_min: null, distance_airport_min: null, infrastructure: [],
  },
  market_context: {
    potential_revenue: null,
    demographics: { population_development: null, purchasing_power: null },
  },
  processing_metadata: {
    document_id: 'error_' + workflowId + '_' + String(now.getTime()),
    source_filename: null,
    ingestion_channel: null,
    processed_at: processedAt,
    status: 'failed',
    validation_errors: [
      'workflow:' + workflowName,
      lastNode ? 'last_node:' + lastNode : null,
      'error:' + errorMessage,
    ].filter(Boolean),
  },
  _runtime: {
    persist_result: true,
    persistence_mode: 'postgres',
    alert_url: null,
    alert_marker: null,
  },
};

return [{ json: payload }];
